   683→    private void gatherRootServices(List<Service> services) throws Exception {
   684→        Endpoint endpoint = getEndpoint();
   685→        consumer = endpoint.createConsumer(processor);
   686→        if (consumer != null) {
   687→            services.add(consumer);
   688→            if (consumer instanceof RouteAware routeAware) {
   689→                routeAware.setRoute(this);
   690→            }
   691→            if (consumer instanceof RouteIdAware routeIdAware) {
   692→                routeIdAware.setRouteId(this.getId());
   693→            }
   694→
   695→            if (consumer instanceof ResumeAware resumeAware && resumeStrategy != null) {
   696→                ResumeAdapter resumeAdapter = AdapterHelper.eval(getCamelContext(), resumeAware, resumeStrategy);
   697→                resumeStrategy.setAdapter(resumeAdapter);
   698→                resumeAware.setResumeStrategy(resumeStrategy);
   699→            }
   700→
   701→            if (consumer instanceof ConsumerListenerAware consumerListenerAware) {
   702→                consumerListenerAware.setConsumerListener(consumerListener);
   703→            }
   704→        }
   705→        if (processor instanceof Service service) {
   706→            services.add(service);
   707→        }
   708→        for (Processor p : onCompletions.values()) {
   709→            if (p instanceof Service service) {
   710→                services.add(service);
   711→            }
   712→        }
   713→        for (Processor p : onExceptions.values()) {
   714→            if (p instanceof Service service) {
   715→                services.add(service);
   716→            }
   717→        }
   718→    }
