   722→    public Navigate<Processor> navigate() {
   723→        Processor answer = getProcessor();
   724→
   725→        // we want to navigate routes to be easy, so skip the initial channel
   726→        // and navigate to its output where it all starts from end user point of view
   727→        if (answer instanceof Navigate nav) {
   728→            if (nav.next().size() == 1) {
   729→                Object first = nav.next().get(0);
   730→                if (first instanceof Navigate) {
   731→                    return (Navigate<Processor>) first;
   732→                }
   733→            }
   734→            return (Navigate<Processor>) answer;
   735→        }
   736→        return null;
   737→    }
