   747→    private void doFilter(String[] patterns, Navigate<Processor> nav, List<Processor> match) {
   748→        List<Processor> list = nav.next();
   749→        if (list != null) {
   750→            for (Processor proc : list) {
   751→                if (proc instanceof Channel channel) {
   752→                    proc = channel.getNextProcessor();
   753→                }
   754→                String id = null;
   755→                if (proc instanceof IdAware idAware) {
   756→                    id = idAware.getId();
   757→                }
   758→                if (PatternHelper.matchPatterns(id, patterns)) {
   759→                    match.add(proc);
   760→                }
   761→                if (proc instanceof Navigate) {
   762→                    Navigate<Processor> child = (Navigate<Processor>) proc;
   763→                    doFilter(patterns, child, match);
   764→                }
   765→            }
   766→        }
