   140→     * beans, and other services that may not be available, or is unwanted to be in use; for example to have fast
   141→     * startup, and being able to introspect CamelContext and the route models.
   142→     */
   143→    public static final String DISABLE_ALL_PROCESSORS = "DisableAllProcessors";
   144→
   145→    /**
   146→     * Global option on {@link CamelContext#getGlobalOptions()} that tooling can use to disable route processors (bean
   147→     * and custom process), which allows to startup Camel without wiring up and initializing using custom
   148→     * bean/processors, that may not be available, or is unwanted to be in use; for example to have fast startup, and
   149→     * being able to introspect CamelContext and the route models.
   150→     */
   151→    public static final String DISABLE_BEAN_OR_PROCESS_PROCESSORS = "DisableBeanOrProcessProcessors";
   152→
   153→    private static final Logger LOG = LoggerFactory.getLogger(ProcessorReifier.class);
   154→
   155→    // for custom reifiers
   156→    private static final Map<Class<?>, BiFunction<Route, ProcessorDefinition<?>, ProcessorReifier<? extends ProcessorDefinition<?>>>> PROCESSORS
   157→            = new HashMap<>(0);
   158→
   159→    protected final T definition;
