   171→    public static void registerReifier(
   172→            Class<?> processorClass,
   173→            BiFunction<Route, ProcessorDefinition<?>, ProcessorReifier<? extends ProcessorDefinition<?>>> creator) {
   174→        if (PROCESSORS.isEmpty()) {
   175→            ReifierStrategy.addReifierClearer(ProcessorReifier::clearReifiers);
   176→        }
   177→        PROCESSORS.put(processorClass, creator);
   178→    }
